INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00030', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「老車站重新整修後，不單是倚老賣老，努力把過往的建築風貌留住，還 想藉由昔時的採煤風情，展現這個小站的獨特性。但規劃者的能力也僅止 於此，一旦踏出前面的公路，旅人很快就被拉回現實，拉回某一衛星城市 的髒亂和失序。」 根據上文，老車站重新規劃後的問題是：', '["新車站的標新立異抹煞歷史的痕跡和價值", "整修後的車站和站前社區缺乏連結和對話", "數位化的車站與當地資訊化落後形成對比", "整體衛生環境髒亂不堪且未受到大家重視"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00031', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「詩不是拿來『讀懂』的，而是用來『感覺』的。有人說，詩是文學中的 貴族，它曖昧且充滿暗號；但詩也很奇妙，當我們讀詩時，將會重新回到 自己人生的某個片刻。」 根據上文，下列選項何者正確？', '["詩不是拿來「讀懂」的，所以一般人無須過度深究、也無須字斟句酌的 閱讀", "詩的「奇妙」之處，在於它能示現真實的畫面，讓每個人都來到作者人 生的某個時刻", "詩是用來「感覺」的，因此讀詩時必須調動讀者的心靈，以感性的態度 體會文字所傳遞的情感", "從「曖昧」、「暗號」等詞，可以知道讀詩需要智慧來解決謎團，所以 「貴族」才能解譯密碼"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00032', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '蘇軾曾寫過一篇小遊記，提及在惠州時，一回遊覽松風亭，不料才走到半 路就腳痠力乏，眼見亭子還在遠遠的林間，苦惱、痛苦不已。良久忽而轉 念，思及「此間有甚麼歇不得處？」一時豁然開朗，感覺自己像是咬住魚 餌的魚忽然掙脫魚鉤那般自在！ 根據上文，下列選項符合蘇軾想法的是：', '["人生行佇坐臥處處皆學問", "人總是高估自己能做到的", "有萬全準備，方可堅持到底", "不需執著，人生沒有那麼難"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00033', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「有人說，幽默像針線，只要靈活運用，就可以彌補事情的缺陷；而人生 好比走鋼索，幽默就是那根平衡桿。有人問我，幽默是天生的還是後天的。 我認為是後天的，只要用心為別人著想，有時候也有雅量調侃自己，就可 培養幽默感，讓身邊的人快樂。我更相信，正因為幽默有利他的成分，一 個處處要占上風的人，是不可能有幽默感，也不會欣賞幽默感的。」 根據上文，下列選項何者最符合文意？', '["用心設計過的幽默，比無心發想的幽默更利他", "幽默感可以後天養成，同理並換位思考很重要", "能容忍他人處處占上風，是培養幽默感的要件", "愛調侃自己的人勿勉強耍幽默，以免弄巧成拙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00034', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「重山曲流外就是苦樂混合著沸騰的紅塵，那裡面也有著我的妻女和親 友，而我卻一個人上山來獨自享受清靜。那麼，我的幸福是不是純由逃避 式的懶散得來的呢？」 根據上文，下列選項最符合作者心理的是：', '["竊喜", "反思", "痛苦", "超然"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00035', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「鞋子的款式，自然顯露了一個人的品味與內涵，但也同時代表了一個人 的心靈狀況。年輕時，總是希望穿著『正式』，讓人家不要一眼看穿我因 缺乏經驗而惶恐的心；也不要認為我無知失禮或不合時宜。但現在慢慢不 再講究了，反而是希望以便捷、舒適為主要考量，到哪都踏著一雙便鞋， 也許就宣示了大叔的天真無畏，諸法皆空。」 根據上文，下列選項何者最符合文意？', '["年輕人相較年長者只追求鞋子的外型", "年長男性不甚講究衣著的正式與流行", "鞋子的樣式呈現出此人的性格與需求", "鞋子的設計最能反映當代的美學趨勢"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00036', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「從與土地及自然相處長出來的知識，是一本怎麼也讀不完的書。地方的 農民往往會說『蘿蔔紮地生長後不能澆太多水，否則會長出像人蔘般的多 根』、『高麗菜在包心的時候也是數日一澆，要不菜心就爆開了』、『菜 苗長出來之後要勤快拔雜草，三兩天拔一次』。在馬祖也可見證大自然的 慷慨與偶爾的無情翻臉，譬如霧季時的十分鐘一氣象，你得順著時節、按 著節奏、勤著腳步、聽著建議、耐著心情，然後作物就會一季季回饋你的 累。」 根據上文，下列選項何者最符合文意？', '["只要用心勤快對待作物，並能吸取種植經驗，作物會以豐收回饋", "蘿蔔、高麗菜等作物無需花費太多心思，只要澆灌就會長得很好", "農作知識靠口耳相傳，正確性不高，照書本種植比較不容易出錯", "必須突破氣候的限制，不分四季殷勤耕耘，才能種出優良的作物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00037', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「一面走動，跟緊外婆怕跟丟，一面忙吃。冰在糖漿裡瞬間就化水，不時 吮一口融冰，才不會走著走著晃出來。且記得把冰遞回給外婆，她也吃上 幾口。這種含糖時刻是祖孫倆放風的樂趣，彼此掩護是為溺愛。兒時的米 苔目時光，都與我外婆一道。長大生出了自己的偏好，多年不吃，兼排斥 一切粗麵。麵吃細麵，吃粉就選米粉米線。米苔目這白胖的粉食，跟粗米 粉被我歸成同一路，覺得味道寡淡。現在回頭去找米苔目，懷念的仍不是 味道，而是童年。」 根據上文，下列選項最符合文意的是：', '["米苔目冰能緩緩化水，吮飲融冰是作者童年時的一大樂趣", "外婆和幼年作者常被禁止吃糖，因此會一起偷吃米苔目冰", "作者雖不愛吃粗麵和粗米粉，仍愛品嚐滋味清淡的米苔目", "作者長大後吃米苔目，除了懷念味道，也是紀念童年時光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00038', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「節約不盡然是苦行僧式的刻苦。我的意思是說，刻苦的概念必然包含抗 拒豐饒的誘惑：拒絕太多食物、太多富足、太多財物、太多享樂。刻苦的 人譴責享樂，認為它容易導致放縱。因此必須節制，減量，排除。刻苦的 概念有一大成分是嚴峻，一種對樂趣的輕視乃至恐懼。刻苦是拒絕自我解 放，禁止讓自己感受程度太深，以免無法節制。節制則是發現簡單能夠帶 來滿足，發現人可以幾乎一無所有——只有一杯清水，一顆水果，一陣涼 風——卻感到無比幸福。」 根據上文，下列選項何者正確？', '["追求刻苦的人生，可拒絕豐饒的誘惑，因而能享受富足", "刻苦的目的是為了讓生活更為簡單，因此完全拒絕生活的享樂", "「節約」是發現簡單能帶來幸福，而不是刻意讓自己感到匱乏與痛苦", "我們應當學習苦行僧式的生活態度，才能讓生活變得更為簡約而自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00039', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「有首曲子，希望用在我的葬禮上。這是第一首讓我大哭的音樂——貝多 芬的『皇帝』鋼琴協奏曲。標題被安上『皇帝』，是因為它誇張的特色。 曲子首尾兩樂章，音符充耳，如煙火散落；中間的第二樂章，極美，平靜， 讓人屏息。我那時比較年輕，不大能駕馭，現在我已長大，音樂能做什麼， 全展現其中。」 根據上文，下列選項最符合文意的是：', '["鋼琴家希望葬禮隆重，樂曲具莊嚴堂皇之風，以切合他的身分", "鋼琴家自認要到晚年，才能駕馭貝多芬炫麗的「皇帝」協奏曲", "貝多芬失聰後作的「皇帝」協奏曲，高低起伏，令鋼琴家仰慕", "「皇帝」協奏曲兼具燦爛、平靜曲風，適合詮釋鋼琴家的一生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
